 3→const DEFAULT_ALLOWED_ORIGINS = ["http://localhost:5173"];
 4→
 5→function normalizeOrigins(value: string | undefined): Set<string> {
 6→  const origins = value
 7→    ?.split(",")
 8→    .map((origin) => origin.trim())
 9→    .filter(Boolean);
10→
11→  return new Set([...(origins ?? []), ...DEFAULT_ALLOWED_ORIGINS]);
12→}
