14→export function getCorsOrigin(origin: string | undefined, env: Bindings): string | null {
15→  if (!origin) {
16→    return null;
17→  }
18→
19→  return normalizeOrigins(env.ALLOWED_ORIGINS).has(origin) ? origin : null;
20→}
