116→function parseDecklist(input: string): { lines: Array<{ qty: number; query: string }>; errors: string[] } {
117→  const lines: Array<{ qty: number; query: string }> = [];
118→  const errors: string[] = [];
119→  const rawLines = input
120→    .split("\n")
121→    .map((line) => line.trim())
122→    .filter(Boolean)
123→    .filter((line) => !line.startsWith("#") && !line.startsWith("//"));
124→
125→  for (const raw of rawLines) {
126→    const match = raw.match(/^(\d+)\s*x?\s+(.+)$/i);
127→    if (!match) {
128→      errors.push(`Could not parse line: "${raw}"`);
129→      continue;
130→    }
131→
132→    const qty = parseInt(match[1], 10);
133→    const query = match[2].trim();
134→    if (!qty || qty < 1) {
135→      errors.push(`Invalid quantity in line: "${raw}"`);
136→      continue;
137→    }
138→    if (!query) {
139→      errors.push(`Missing card name/id in line: "${raw}"`);
140→      continue;
141→    }
142→    lines.push({ qty, query });
143→  }
144→
145→  return { lines, errors };
146→}
147→
148→function shuffle<T>(arr: T[]): T[] {
149→  const out = [...arr];
150→  for (let i = out.length - 1; i > 0; i -= 1) {
151→    const j = Math.floor(Math.random() * (i + 1));
152→    [out[i], out[j]] = [out[j], out[i]];
153→  }
154→  return out;
155→}
156→
157→function drawFromDeck<T>(deck: T[], count: number): T[] {
158→  const out: T[] = [];
159→  for (let i = 0; i < count && deck.length > 0; i += 1) {
160→    const card = deck.shift();
161→    if (card) out.push(card);
162→  }
163→  return out;
164→}
165→
166→function hasBasicInHand(hand: CardInstance[]): boolean {
167→  return hand.some((card) => card.card.category === "Pokemon" && card.card.stage === "Basic");
168→}
169→
170→function autoMulliganUntilBasic(player: Pick<PlayerBoard, "hand" | "deck" | "mulligans">) {
171→  if (!hasBasicInHand([...player.hand, ...player.deck])) return false;
172→  while (!hasBasicInHand(player.hand)) {
173→    player.mulligans += 1;
174→    player.deck = shuffle([...player.deck, ...player.hand]);
175→    player.hand = drawFromDeck(player.deck, 7);
176→  }
177→  return true;
178→}
