180→function createEmptyPlayer(): PlayerBoard {
181→  return {
182→    deck: [],
183→    hand: [],
184→    prizes: [],
185→    discard: [],
186→    active: null,
187→    bench: [],
188→    takenPrizes: 0,
189→    mulligans: 0,
190→    trainerUseZone: [],
191→    energyAttachedThisTurn: false,
192→    supporterPlayedThisTurn: false,
193→    retreatedThisTurn: false,
194→    activeEffects: [],
195→  };
196→}
