198→async function buildDeck(c: any, input: string, label: string, nextUid: () => string) {
199→  const parsed = parseDecklist(input);
200→  if (parsed.errors.length > 0) {
201→    return { deck: null, errors: parsed.errors.map((error) => `${label}: ${error}`) };
202→  }
203→
204→  const cache = new Map<string, CardSummary | null>();
205→  const uniqueQueries = [...new Set(parsed.lines.map((line) => line.query))];
206→  for (const query of uniqueQueries) {
207→    const card = looksLikeCardId(query)
208→      ? await loadCardById(c, query.trim())
209→      : await searchCardByName(c, query);
210→    cache.set(query, card);
211→  }
212→
213→  const deck: CardInstance[] = [];
214→  const errors: string[] = [];
215→  for (const line of parsed.lines) {
216→    const card = cache.get(line.query) ?? null;
217→    if (!card) {
218→      errors.push(`${label}: card not found for "${line.query}".`);
219→      continue;
220→    }
221→    for (let i = 0; i < line.qty; i += 1) {
222→      deck.push({ uid: nextUid(), card: card as CardSummary });
223→    }
224→  }
225→
226→  if (errors.length > 0) {
227→    return { deck: null, errors };
228→  }
229→  if (deck.length !== 60) {
230→    return { deck: null, errors: [`${label}: deck has ${deck.length} cards. It must have exactly 60.`] };
231→  }
232→
233→  return { deck: shuffle(deck), errors: [] };
234→}
