236→function isRecord(value: unknown): value is Record<string, unknown> {
237→  return typeof value === "object" && value !== null;
238→}
239→
240→function isPlayerIndex(value: unknown): value is 0 | 1 {
241→  return value === 0 || value === 1;
242→}
243→
244→function isSimulatorStore(value: unknown): value is SimulatorStore {
245→  return (
246→    isRecord(value) &&
247→    (value.phase === "idle" || value.phase === "setup" || value.phase === "playing") &&
248→    Array.isArray(value.players) &&
249→    value.players.length === 2 &&
250→    isPlayerIndex(value.currentTurn) &&
251→    isPlayerIndex(value.firstPlayer) &&
252→    Array.isArray(value.stadiumUsedThisTurn) &&
253→    value.stadiumUsedThisTurn.length === 2
254→  );
255→}
256→
257→function isNewGameBody(value: unknown): value is { deck1: string; deck2: string } {
258→  return isRecord(value) && typeof value.deck1 === "string" && typeof value.deck2 === "string";
259→}
260→
261→function isDragPayload(value: unknown): value is { playerIdx: 0 | 1; uid: string; zone: "hand" | "active" | "bench" | "prize" } {
262→  return (
263→    isRecord(value) &&
264→    isPlayerIndex(value.playerIdx) &&
265→    typeof value.uid === "string" &&
266→    (value.zone === "hand" || value.zone === "active" || value.zone === "bench" || value.zone === "prize")
267→  );
268→}
269→
270→function isSimulatorAction(value: unknown): value is SimulatorAction {
271→  if (!isRecord(value) || typeof value.type !== "string") return false;
272→  switch (value.type) {
273→    case "selectPrize":
274→    case "selectHandCard":
275→      return isPlayerIndex(value.playerIdx) && typeof value.uid === "string";
276→    case "deselectHandCard":
277→      return isPlayerIndex(value.playerIdx);
278→    case "dropToActive":
279→    case "dropToBench":
280→    case "dropToDiscard":
281→    case "dropToHand":
282→      return isDragPayload(value.payload) && isPlayerIndex(value.targetPlayerIdx);
283→    case "dropToBenchSlot":
284→      return isDragPayload(value.payload) && isPlayerIndex(value.targetPlayerIdx) && typeof value.benchIdx === "number";
285→    case "dropToStadium":
286→    case "dropToTrainerUse":
287→      return isDragPayload(value.payload);
288→    case "useAttack":
289→      return typeof value.attackIdx === "number";
290→    case "useAbility":
291→      return typeof value.pokemonUid === "string" && typeof value.abilityIdx === "number";
292→    case "playTrainerCard":
293→    case "toggleHandSelectionCard":
294→    case "toggleDeckSearchCard":
295→    case "toggleDiscardSelectionCard":
296→    case "toggleEvolveFromDeckCard":
297→    case "toggleBenchDiscardCard":
298→      return typeof value.uid === "string";
299→    case "confirmOpponentSwitch":
300→    case "confirmSelfSwitch":
301→    case "retreat":
302→      return typeof value.benchUid === "string";
303→    case "confirmHandSelection":
304→    case "confirmDeckSearch":
305→    case "cancelDeckSearch":
306→    case "confirmDiscardSelection":
307→    case "cancelDiscardSelection":
308→    case "cancelOpponentSwitch":
309→    case "cancelSelfSwitch":
310→    case "cancelRareCandy":
311→    case "confirmEvolveFromDeck":
312→    case "cancelEvolveFromDeck":
313→    case "confirmBenchDiscard":
314→    case "useStadiumAbility":
315→    case "endTurn":
316→      return true;
317→    default:
318→      return false;
319→  }
320→}
