 1→import { Hono } from "hono";
 2→import type { AppEnv } from "../types";
 3→import { getCorsOrigin } from "../lib/cors";
 4→
 5→const imagesRoute = new Hono<AppEnv>();
 6→
 7→imagesRoute.get("/*", async (c) => {
 8→  const key = c.req.path.replace(/^\/images\//, "");
 9→  if (!key) {
10→    return c.json({ error: "Missing key" }, 400);
11→  }
12→
13→  const cache = caches.default;
14→  const cacheKey = c.req.raw;
15→
16→  const cached = await cache.match(cacheKey);
17→  if (cached) {
18→    return new Response(cached.body, cached);
19→  }
20→
21→  const object = await c.env.IMAGES.get(key);
22→  if (!object) {
23→    return c.json({ error: "Not found" }, 404);
24→  }
25→
26→  const headers = new Headers();
27→  headers.set(
28→    "Content-Type",
29→    object.httpMetadata?.contentType || "application/octet-stream",
30→  );
31→  headers.set("Cache-Control", "public, max-age=31536000, immutable");
32→  headers.set("ETag", object.etag);
33→
34→  const origin = getCorsOrigin(c.req.header("Origin"), c.env);
35→  if (origin) {
36→    headers.set("Access-Control-Allow-Origin", origin);
37→    headers.set("Vary", "Origin");
38→  }
39→
40→  const response = new Response(object.body, { headers });
41→
42→  c.executionCtx.waitUntil(cache.put(cacheKey, response.clone()));
43→
44→  return response;
45→});
46→
47→export { imagesRoute };
